-const GOOGLE_TURN_ORDERING_CUSTOM_TYPE = "google-turn-ordering-bootstrap";
-const GOOGLE_SCHEMA_UNSUPPORTED_KEYWORDS = new Set([
-  "patternProperties",
-  "additionalProperties",
-  "$schema",
-  "$id",
-  "$ref",
-  "$defs",
-  "definitions",
-  "examples",
-  "minLength",
-  "maxLength",
-  "minimum",
-  "maximum",
-  "multipleOf",
-  "pattern",
-  "format",
-  "minItems",
-  "maxItems",
-  "uniqueItems",
-  "minProperties",
-  "maxProperties",
-]);
